  ('bookkeeper-moex-00789', 'bookkeeper', 'bookkeeper-moex-108-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '贈與人有以下何種情形，以受贈人為納稅義務人？①行蹤不明  ②和受贈人屬二親等以內親屬  ③逾法', '["死亡時贈與稅尚未核課", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:24+00:00", "source_pdf_sha1": "649483717ea0", "answer_pdf_sha1": "e003a99a2c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 45, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
